const RecommendedMoviesContext = React.createContext({
    bookmarksIsShown: false,
    show_Hide_Bookmarks: () => {},
    recommendedMovie: [],
    updateRecommended: () => {},
    searchResult: {},
    updateSearchResult: () => {},
});

export default RecommendedMoviesContext;
export const Provider = (props) => {
    const [movies, updateRecommendedMovies] = useState([]);
    const [searchResult, updateSearch] = useState({});
    const [bookmarksIsShown, show_Hide_Bookmarks] = useState(false);
    const value = {
        bookmarksIsShown: bookmarksIsShown,
        show_Hide_Bookmarks: show_Hide_Bookmarks,
